#include <vector>
#include <unordered_map>
using namespace std;

int popcount(long long x) {
    int count = 0;
    while (x) {
        count += x & 1;
        x >>= 1;
    }
    return count;
}

int getDepth(long long x, unordered_map<long long, int>& depthCache) {
    if (x == 1) return 0;
    if (depthCache.find(x) != depthCache.end()) {
        return depthCache[x];
    }
    int next = popcount(x);
    int depth = 1 + getDepth(next, depthCache);
    depthCache[x] = depth;
    return depth;
}

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    unordered_map<long long, int> depthCache;
    vector<vector<int>> prefix(6, vector<int>(nums.size() + 1, 0));

    // Precompute prefix sums for each possible k (0 to 5)
    for (int k = 0; k <= 5; ++k) {
        for (int i = 0; i < nums.size(); ++i) {
            int d = getDepth(nums[i], depthCache);
            prefix[k][i+1] = prefix[k][i] + (d == k ? 1 : 0);
        }
    }

    vector<long long> answer;
    for (const auto& query : queries) {
        if (query[0] == 1) {
            long long l = query[1];
            long long r = query[2];
            int k = query[3];
            if (k < 0 || k > 5) {
                answer.push_back(0);
                continue;
            }
            int count = prefix[k][r+1] - prefix[k][l];
            answer.push_back(count);
        } else if (query[0] == 2) {
            long long idx = query[1];
            long long val = query[2];
            int old_depth = getDepth(nums[idx], depthCache);
            nums[idx] = val;
            int new_depth = getDepth(val, depthCache);

            // Update prefix sums for all k
            for (int k = 0; k <= 5; ++k) {
                int delta = (new_depth == k ? 1 : 0) - (old_depth == k ? 1 : 0);
                for (int i = idx + 1; i <= nums.size(); ++i) {
                    prefix[k][i] += delta;
                }
            }
        }
    }
    return answer;
}
